import { orders, products, getNextOrderId } from "../data.js";
import { NotFoundError, ValidationError } from "../errors.js";
import type { CreateOrderInput, OrderItem } from "../types.js";

export interface OrderFilters {
  userId?: number;
  status?: string;
}

const VALID_STATUSES = ["pending", "confirmed", "shipped", "delivered"];

const STATUS_TRANSITIONS: Record<string, string[]> = {
  pending: ["confirmed"],
  confirmed: ["shipped"],
  shipped: ["delivered"],
  delivered: [],
};

export function listOrders(filters: OrderFilters) {
  let filtered = [...orders];

  if (filters.userId !== undefined) {
    filtered = filtered.filter((o) => o.userId === filters.userId);
  }

  if (filters.status !== undefined) {
    filtered = filtered.filter((o) => o.status === filters.status);
  }

  const totalRevenue = filtered.reduce((sum, o) => sum + o.total, 0);

  return {
    orders: filtered,
    summary: {
      count: filtered.length,
      totalRevenue: Math.round(totalRevenue * 100) / 100,
    },
  };
}

export function getOrder(id: number) {
  const order = orders.find((o) => o.id === id);
  if (!order) throw new NotFoundError("Order not found");

  const enrichedItems = order.items.map((item) => {
    const product = products.find((p) => p.id === item.productId);
    return {
      ...item,
      productName: product?.name ?? "Unknown",
    };
  });

  return {
    ...order,
    items: enrichedItems,
  };
}

export function createOrder(input: CreateOrderInput) {
  if (!input.userId || !input.items || !Array.isArray(input.items)) {
    throw new ValidationError("userId and items are required");
  }

  if (input.items.length === 0) {
    throw new ValidationError("Order must have at least one item");
  }

  const orderItems: OrderItem[] = [];
  let total = 0;

  for (const item of input.items) {
    const product = products.find((p) => p.id === item.productId);
    if (!product) {
      throw new ValidationError(`Product ${item.productId} not found`);
    }

    if (item.quantity <= 0) {
      throw new ValidationError("Quantity must be positive");
    }

    if (product.stock < item.quantity) {
      throw new ValidationError(`Insufficient stock for ${product.name}`);
    }

    product.stock -= item.quantity;

    orderItems.push({
      productId: product.id,
      quantity: item.quantity,
      price: product.price,
    });
    total += product.price * item.quantity;
  }

  const order = {
    id: getNextOrderId(),
    userId: input.userId,
    items: orderItems,
    total: Math.round(total * 100) / 100,
    status: "pending" as const,
    createdAt: new Date().toISOString(),
  };

  orders.push(order);

  return order;
}

export function updateOrderStatus(id: number, status: string) {
  const order = orders.find((o) => o.id === id);
  if (!order) throw new NotFoundError("Order not found");

  if (!VALID_STATUSES.includes(status)) {
    throw new ValidationError(
      `Invalid status. Must be one of: ${VALID_STATUSES.join(", ")}`
    );
  }

  if (!STATUS_TRANSITIONS[order.status]?.includes(status)) {
    throw new ValidationError(
      `Cannot transition from ${order.status} to ${status}`
    );
  }

  order.status = status as typeof order.status;

  return order;
}

